import React, { useState } from "react";
import axios from "axios";

const Login = () => {
  const [form, setForm] = useState({});

  const handle = (e) =>
    setForm({ ...form, [e.target.name]: e.target.value });

  const submit = async () => {
    const res = await axios.post("http://localhost:5000/api/auth/login", form);

    localStorage.setItem("user", JSON.stringify(res.data.user));

    if (res.data.user.role === "customer")
      window.location.href = "/customer";
    else
      window.location.href = "/labour";
  };

  return (
    <div style={styles.container}>

      <div style={styles.card}>
        <h2>Login</h2>

        <input name="email" placeholder="Email" onChange={handle} style={styles.input}/>
        <input name="password" placeholder="Password" onChange={handle} style={styles.input}/>

        <button onClick={submit} style={styles.btn}>
          Login
        </button>
      </div>

    </div>
  );
};

export default Login;

const styles = {
  container: {
    height: "100vh",
    background: "#0b1220",
    display: "flex",
    justifyContent: "center",
    alignItems: "center"
  },

  card: {
    background: "#111a2e",
    padding: "30px",
    borderRadius: "12px",
    width: "300px",
    color: "white"
  },

  input: {
    width: "100%",
    padding: "10px",
    margin: "10px 0"
  },

  btn: {
    width: "100%",
    padding: "10px",
    background: "#22c55e",
    border: "none",
    color: "white"
  }
};
